var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAE","text":{"KOREA":"으윽…… 몸이 왜 이러지…… 너무 오랫동안 플레이했나……?","JPN":"ううっ……体が……長くプレイしすぎたかな……？","ENG":"Ngh... What's wrong with my body...? Have I been playing for too long...?","TWN":"呃……身體怎麼了……是不是玩太久了……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PLAYER_LAGACY_NULL_EXTRAE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"저기 봐! 저 녀석, 몸이 꼭 침식체처럼 변하고 있어!","JPN":"見て！　あいつ、体が侵食体みたいに変化してる！","ENG":"Hey, look! It looks like his body is turning into a C.O.!","TWN":"看那邊！那傢伙的身體像侵蝕體一樣在變化！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"일났구마, 점점 그림자처럼 되어가고 있는 기다.","JPN":"参ったな、だんだんシャドウみたいに変化しとるんや。","ENG":"That ain't good. He's 'bout to turn into a Shadow.","TWN":"出事了，越來越像暗影了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"사람들의 바람을 이미지화시키는 오버로드가 부정적인 바람까지 실체화시키고 있는 거지.","JPN":"人々の望みを実体化するオーバーロードが、ネガティブな望みまで実体化してるんや。","ENG":"Overlord turns people's wishes into images, and now it's even fulfilling the negative wishes.","TWN":"將人們的願望具象化的超載，正在將負面的願望也實體化。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"즉, 이제 카운터즈 레거시라는건 이면세계가 된 거나 다름없는 기다!","JPN":"もうカウンターズ・レガシーは裏世界同然や。","ENG":"In other words, Counters Legacy has become the Counterside!","TWN":"也就是說，現在所謂的制裁者的遺產已經變成了異界了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"무, 무슨 헛소리야?! 이건 그냥 게임일 뿐이잖아!","JPN":"な、何バカのこと言ってるの？　これはただのゲームでしょ！？","ENG":"W-what are you talking about?! This is just a game!","TWN":"你，你在胡說什麼？！這只是個遊戲而已！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"마! 그냥 게임이라고?","JPN":"ただのゲームやと？","ENG":"What?! Just a game?","TWN":"哈！只是遊戲嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아이다. 이제 이건 게임이 아니라 일종의 침식 재난인기다!","JPN":"これはもうゲームちゃうで、一種の侵食災難や！","ENG":"No, it ain't. It ain't just a game. It's a kind of a Corruption disaster!","TWN":"哎呀，這已經不是遊戲，而是一種侵蝕災難了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAE","text":{"KOREA":"엇, 저건 분명 랭커 아닌가……? 이런 행운이……!","JPN":"あれ？　あの人は確かランカーの……？　ラッキー……！","ENG":"Huh? Isn't that a top ranker...? It's my lucky day...!","TWN":"咦，那不是排名前段班的嗎……？真是好運……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PLAYER_LAGACY_NULL_EXTRAE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAE","text":{"KOREA":"아하하, 나도 당신들처럼 강한 카운터가 되고 싶었는데, 혹시 괜찮으면 같이 파티를…….","JPN":"あはは、私もあなたたちみたいな強いカウンターになりたかったんだ。もしよかったら一緒にパーティーを……","ENG":"Ah hah hah. I wanted to become a strong Counter like you. So, could I join your party if you don't mind–","TWN":"哈哈哈，我也想成為像你們一樣強大的制裁者。如果可以的話，一起組隊吧……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PLAYER_LAGACY_NULL_EXTRAE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"어이! 당장 로그아웃해라! 네 지금 침식체가 되어가는 거 못 느끼나?","JPN":"おい！　今すぐログアウトせなあかん！　あんたの体、侵食体になっとるで！","ENG":"Hey! Log out right now! Cn't ya tell that you're turnin' into a C.O.?","TWN":"喂！立刻登出！你沒感覺到自己正在變成侵蝕體嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PLAYER_LAGACY_NULL_EXTRAE","face":"UNIT_IDLE"},"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAE","text":{"KOREA":"무, 무슨 소리야……? 난 이렇게나 멀쩡한데……?","JPN":"ど、どういうこと……？　私は普通なのに……？","ENG":"W-what are you talking about...? I feel fine...","TWN":"什，什麼意思啊……？我明明好好的……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PLAYER_LAGACY_NULL_EXTRAE","text":{"KOREA":"어, 어라……? 어째서 내 모습이……?","JPN":"あ、あれ……？　どうして私の姿が……？","ENG":"H-huh...? Why do I look like this...?","TWN":"呃，啊啊……？為什麼我的樣子……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"데이터 로스트…… 로그아웃되었어.","JPN":"データロスト……ログアウトされた。","ENG":"Data lost... He got logged out.","TWN":"數據遺失……已登出。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"제때 도착해서 다행이다. 조금만 늦었어도 큰일 났을 거야.","JPN":"間に合ってよかったわ。あと少し遅かったら大変なことになってたはず。","ENG":"Thank goodness I arrived right on time. It would've been a disaster if I was even a little late.","TWN":"幸虧到的及時，再晚一點就糟糕了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"니들 인자 왔나? 그럼 방금 금마는 어떻게 된 건데?","JPN":"やっと来たか。さっきのやつはどうなった？","ENG":"Y'all just got here? What happened to that fella?","TWN":"你們現在才來？那剛才那傢伙是怎麼回事？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"돌아갔어……. 현실로.","JPN":"帰った……現実に。","ENG":"He went back... to reality.","TWN":"回去了……回到現實世界。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"무사할 거야……. 분명.","JPN":"無事だよ……きっと。","ENG":"I'm sure... he's safe.","TWN":"一定會平安無事的……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"당신들이 여기 왔다는 건 해결책을 들고 왔다는 거 맞지?","JPN":"あんたたちが来たってことは、解決策が見つかったってことよね。","ENG":"Seeing how you are all here, that means you found a solution, no?","TWN":"你們來這裡是帶來了解決方案吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"개발해 왔어…… 바이러스.","JPN":"開発した……ウィルス。","ENG":"I developed... a virus.","TWN":"開發了……病毒。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"이걸로…… 파괴할 거야. 카운터즈 레거시의 시스템.","JPN":"これで……破壊する。カウンターズ・レガシーのシステム。","ENG":"With this... I will destroy. Counters Legacy's system.","TWN":"用這個……摧毀……制裁者的遺產的系統。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐, 뭐?! 너무 1차원적인 방법이잖아!","JPN":"は、はあ！？　そんなの短絡的すぎない！？","ENG":"W-what?! Don't you think that's too simple of a solution?!","TWN":"什，什麼？！這麼簡單粗暴的方法！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"오버로드와 결합된 시스템 자체를 파괴하면, 더 이상 침식현상은 일어나지 않을 거야.","JPN":"オーバーロードと結合したシステム全てを破壊すれば、これ以上侵食現象は起こらないわ。","ENG":"If we destroy the system that has merged with Overlord itself, the Counterside Effect will stop.","TWN":"如果破壞與超載結合的系統，侵蝕現象將不再發生。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"시스템 파괴로 인한 로그아웃은 유저들에게 후유증이 남을지도 모르지만, 다른 방법이 없어.","JPN":"システム破壊によるログアウトが、ユーザーたちに後遺症を残すかもしれないけど、他に方法がないの。","ENG":"The destruction of the system may cause some aftereffects to players who didn't log out beforehand, but there is no other way.","TWN":"由於系統破壞導致的登出可能會給玩家留下後遺症，但沒有其他辦法。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"돌이킬 수 없어……. 지체했다간.","JPN":"取り返しがつかなくなる……遅くなると。","ENG":"There is no going back... if we delay it.","TWN":"無法挽回了……再拖下去的話。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};